import os
import urllib.request
import torch
from torch import nn, optim

class TransferLearningPipeline():
    def __init__(self, model_url):
        self.model_url = model_url
        self.device = "cuda" if torch.cuda.is_available() else "cpu"
        
    def download_pretrained_models(self):
        # Create directory to save models
        os.makedirs("pretrained", exist_ok=True)
        
        print('Downloading pretrained model...')
        urllib.request.urlretrieve(self.model_url, 'pretrained/model.pth')
        print('Model downloaded successfully!')
    
    def load_checkpoint(self):
        # Load checkpoint
        print('Loading model from checkpoint...')
        self.model = torch.load('pretrained/model.pth').to(self.device) 
        print('Checkpoint loaded successfully!')
        
    def fine_tune(self, dataset):
        # Set the fine-tuning model to train mode
        self.model.train()
        
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.SGD(self.model.parameters(), lr=0.01)
        
        print('Starting Fine Tuning...')
        for epoch in range(10):  # Run for multiple epochs (or until convergence)
            running_loss = 0
            for data, target in dataset:
                data = data.to(self.device)
                target = target.to(self.device)
                
                optimizer.zero_grad()  
                
                output = self.model(data)
                loss = criterion(output, target)
                
                running_loss += float(loss) * data.size(0)
                
                # Backward pass
                loss.backward()
                optimizer.step()
            print('Epoch: {} - Loss: {:.6f}'.format(epoch + 1, running_loss / len(dataset))) 
            
        print('Fine tuning finished!')